#include<bits/stdc++.h>
using namespace std;
unsigned long long n,m,p,cost,mine=10000000;
double sum;
int main() {
	cin>>n;
	for(unsigned long long i=0; i<3; i++) {
		cin>>m>>p;
		sum=ceil(n/(m*1.0));
		cost=sum*p;
		if(cost<mine) {
			mine=cost;
		}
	}
	cout<<mine;
	return 0;
}
